import models from '../models'
import { AdminService } from '../services/admin'
import { BaseService, FireService, Service } from '../services/base'



const modelMixin = {
    props: {
        model: {
            type: models.BaseModel,
            required: true,
            default: 'Test'
        },
        service: {
            type: BaseService || AdminService || FireService || Service,
            required: true,
            default: () => new BaseService('test')
        },
        adminService: {
            type: Object,
            required: true,
            default: () => new AdminService()
        }
    },
    data() {
        return {
            fields: []
        }
    },
    methods: {
        initFields() {
            this.fields = this.model.fields().filter((item:any)=> !item.hide)

        }
    },
    created() {
        this.initFields()
    }
}

export default modelMixin